  async function loadBranches() {
    const locationSelect = document.getElementById('location');
    try {
      const response = await fetch('/api/branches');
      if (!response.ok) throw new Error('Failed to fetch branches');

      const branches = await response.json();

      // Clear loading message and populate dropdown
      locationSelect.innerHTML = '<option value="">Kies locatie...</option>';
      branches.forEach(branch => {
        const option = document.createElement('option');
        option.value = branch.id;
        option.textContent = branch.name;
        locationSelect.appendChild(option);
      });
    } catch (error) {
      console.error('Error loading branches:', error);
      locationSelect.innerHTML = '<option value="">Fout bij laden van vestigingen</option>';
    }
  }

  // Load branches when the page loads
  document.addEventListener('DOMContentLoaded', loadBranches);
</script>
